143→        "If you have an existing document (like a plan or spec), you can drop it in and I'll extract everything from it.",
144→      ].join(" ");
145→
146→  const transaction = await deps.surreal.beginTransaction();
147→  try {
148→    await transaction.create(workspaceRecord).content({
149→      name: parsed.data.name,
150→      ...(parsed.data.description ? { description: parsed.data.description } : {}),
151→      ...(parsed.data.repoPath ? { repo_path: parsed.data.repoPath } : {}),
152→      status: "active",
153→      onboarding_complete: false,
154→      onboarding_turn_count: 0,
155→      onboarding_summary_pending: false,
156→      onboarding_started_at: now,
157→      created_at: now,
158→      updated_at: now,
159→    });
160→
161→    await transaction.create(conversationRecord).content({
162→      createdAt: now,
163→      updatedAt: now,
164→      workspace: workspaceRecord,
165→      source: "onboarding",
166→      title: "Onboarding",
