281→async function resolveWorkspaceBootstrapConversation(
282→  deps: ServerDependencies,
283→  workspaceRecord: RecordId<"workspace", string>,
284→): Promise<RecordId<"conversation", string>> {
285→  const [onboardingRows] = await deps.surreal
286→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
287→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace AND source = 'onboarding' ORDER BY createdAt ASC LIMIT 1;",
288→      {
289→        workspace: workspaceRecord,
290→      },
291→    )
292→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
293→
294→  if (onboardingRows.length > 0) {
295→    return onboardingRows[0].id;
296→  }
297→
298→  const [latestRows] = await deps.surreal
299→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
300→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace ORDER BY createdAt DESC LIMIT 1;",
301→      {
302→        workspace: workspaceRecord,
303→      },
304→    )
305→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
306→
307→  if (latestRows.length > 0) {
308→    return latestRows[0].id;
309→  }
310→
311→  const now = new Date();
312→  const conversationRecord = new RecordId("conversation", randomUUID());
313→  await deps.surreal.create(conversationRecord).content({
314→    createdAt: now,
315→    updatedAt: now,
316→    workspace: workspaceRecord,
317→    source: "onboarding",
318→  });
319→  return conversationRecord;
320→}
