322→async function loadWorkspaceSeeds(
323→  deps: ServerDependencies,
324→  workspaceRecord: RecordId<"workspace", string>,
325→  limit: number,
326→): Promise<OnboardingSeedItem[]> {
327→  const [edgeRows] = await deps.surreal
328→    .query<[ProvenanceEdgeRow[]]>(
329→      [
330→        "SELECT id, `in`, out, confidence, extracted_at",
331→        "FROM extraction_relation",
332→        "WHERE `in` IN array::concat(",
333→        "  (SELECT VALUE id FROM message WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)),",
334→        "  (SELECT VALUE id FROM document_chunk WHERE workspace = $workspace)",
335→        ")",
336→        "ORDER BY extracted_at DESC",
337→        "LIMIT $limit;",
338→      ].join(" "),
339→      {
340→        workspace: workspaceRecord,
341→        limit,
342→      },
343→    )
344→    .collect<[ProvenanceEdgeRow[]]>();
345→
346→  const items: OnboardingSeedItem[] = [];
347→
348→  for (const edge of edgeRows) {
349→    const entityText = await readEntityText(deps.surreal, edge.out);
350→    if (!entityText) {
351→      continue;
352→    }
353→
354→    const sourceTable = edge.in.table.name;
355→    const entityTable = edge.out.table.name;
356→    const sourceKind = (sourceTable === "document_chunk" ? "document_chunk" : "message") as SourceKind;
357→    const sourceLabel = await readSourceLabel(deps, edge.in);
358→
359→    items.push({
360→      id: edge.out.id as string,
361→      kind: entityTable as EntityKind,
362→      text: entityText,
363→      confidence: edge.confidence,
364→      sourceKind,
365→      sourceId: edge.in.id as string,
366→      ...(sourceLabel ? { sourceLabel } : {}),
367→    });
368→  }
369→
370→  return items;
371→}
372→
373→async function readSourceLabel(deps: ServerDependencies, sourceRecord: SourceRecord): Promise<string | undefined> {
374→  const sourceTable = sourceRecord.table.name;
375→  if (sourceTable === "message") {
376→    const row = await deps.surreal.select<{ text: string }>(sourceRecord);
377→    if (!row) {
378→      return undefined;
379→    }
380→    return row.text.slice(0, 140);
381→  }
382→
383→  const chunk = await deps.surreal.select<{
384→    section_heading?: string;
385→    document: RecordId<"document", string>;
386→  }>(sourceRecord);
387→
388→  if (!chunk) {
389→    return undefined;
390→  }
391→
392→  const document = await deps.surreal.select<{ name: string }>(chunk.document);
393→  if (!document) {
394→    return chunk.section_heading;
395→  }
396→
397→  if (chunk.section_heading) {
398→    return `${document.name} · ${chunk.section_heading}`;
399→  }
400→
401→  return document.name;
402→}
