593→// ---------------------------------------------------------------------------
594→// GET /api/workspaces/:workspaceId/settings
595→// ---------------------------------------------------------------------------
596→
597→type EnforcementTransitionRow = {
598→  from: string;
599→  to: string;
600→  trigger: "auto" | "manual";
601→  timestamp: Date | string;
602→};
603→
604→type WorkspaceSettingsRow = {
605→  evidence_enforcement?: string;
606→  evidence_enforcement_threshold?: {
607→    min_decisions?: number;
608→    min_tasks?: number;
609→  };
610→  evidence_enforcement_transitions?: EnforcementTransitionRow[];
611→};
612→
613→type EnforcementTransitionResponse = {
614→  from: string;
615→  to: string;
616→  trigger: "auto" | "manual";
617→  timestamp: string;
618→};
619→
620→type WorkspaceSettingsResponse = {
621→  enforcementMode: string;
622→  thresholds: {
623→    min_decisions: number;
624→    min_tasks: number;
625→  };
626→  transitions: EnforcementTransitionResponse[];
627→};
628→
629→const VALID_ENFORCEMENT_MODES: ReadonlySet<string> = new Set(["bootstrap", "soft", "hard"]);
630→
631→async function resolveSessionIdentity(
632→  deps: ServerDependencies,
633→  request: Request,
634→): Promise<{ personRecord: RecordId<"person", string> } | Response> {
635→  const session = await deps.auth.api.getSession({ headers: request.headers });
636→  if (!session?.user?.id) {
637→    return jsonError("authentication required", 401);
638→  }
639→
640→  const personRecord = new RecordId("person", session.user.id);
641→
642→  const [identityRows] = await deps.surreal.query<[RecordId<"identity", string>[]]>(
643→    "SELECT VALUE in FROM identity_person WHERE out = $person LIMIT 1;",
644→    { person: personRecord },
645→  );
646→  if (!identityRows[0]) {
647→    return jsonError("identity not found for user", 401);
648→  }
649→
650→  return { personRecord };
651→}
652→
653→function isSettingsResponse(value: unknown): value is Response {
654→  return value instanceof Response;
655→}
656→
657→function formatTransition(transition: EnforcementTransitionRow): EnforcementTransitionResponse {
658→  const timestamp = transition.timestamp instanceof Date
659→    ? transition.timestamp.toISOString()
660→    : typeof transition.timestamp === "string"
661→      ? transition.timestamp
662→      : new Date(transition.timestamp as unknown as number).toISOString();
663→  return {
664→    from: transition.from,
665→    to: transition.to,
666→    trigger: transition.trigger,
667→    timestamp,
668→  };
669→}
670→
671→function toSettingsResponse(row: WorkspaceSettingsRow): WorkspaceSettingsResponse {
672→  return {
673→    enforcementMode: row.evidence_enforcement ?? "bootstrap",
674→    thresholds: {
675→      min_decisions: row.evidence_enforcement_threshold?.min_decisions ?? 0,
676→      min_tasks: row.evidence_enforcement_threshold?.min_tasks ?? 0,
677→    },
678→    transitions: (row.evidence_enforcement_transitions ?? []).map(formatTransition),
679→  };
680→}
681→
682→async function handleGetSettings(
683→  deps: ServerDependencies,
684→  workspaceId: string,
685→  request: Request,
686→): Promise<Response> {
687→  const identityOrError = await resolveSessionIdentity(deps, request);
688→  if (isSettingsResponse(identityOrError)) return identityOrError;
689→
690→  try {
691→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
692→
693→    const [rows] = await deps.surreal.query<[WorkspaceSettingsRow[]]>(
694→      "SELECT evidence_enforcement, evidence_enforcement_threshold, evidence_enforcement_transitions FROM $ws;",
695→      { ws: workspaceRecord },
696→    );
697→
698→    if (!rows[0]) {
699→      return jsonError("workspace not found", 404);
700→    }
701→
702→    return jsonResponse(toSettingsResponse(rows[0]), 200);
703→  } catch (error) {
704→    if (error instanceof HttpError) {
705→      return jsonError(error.message, error.status);
706→    }
707→
708→    log.error("workspace.settings.get.failed", "Failed to get workspace settings", error, { workspaceId });
709→    return jsonError("failed to get workspace settings", 500);
710→  }
711→}
