713→// ---------------------------------------------------------------------------
714→// PUT /api/workspaces/:workspaceId/settings
715→// ---------------------------------------------------------------------------
716→
717→async function handlePutSettings(
718→  deps: ServerDependencies,
719→  workspaceId: string,
720→  request: Request,
721→): Promise<Response> {
722→  const identityOrError = await resolveSessionIdentity(deps, request);
723→  if (isSettingsResponse(identityOrError)) return identityOrError;
724→
725→  let body: unknown;
726→  try {
727→    body = await request.json();
728→  } catch {
729→    return jsonError("Request body must be valid JSON", 400);
730→  }
731→
732→  if (!body || typeof body !== "object") {
733→    return jsonError("Body must be an object", 400);
734→  }
735→
736→  const { enforcementMode, thresholds } = body as {
737→    enforcementMode?: string;
738→    thresholds?: { min_decisions?: number; min_tasks?: number };
739→  };
740→
741→  // Validate enforcementMode if provided
742→  if (enforcementMode !== undefined) {
743→    if (typeof enforcementMode !== "string" || !VALID_ENFORCEMENT_MODES.has(enforcementMode)) {
744→      return jsonError(`enforcementMode must be one of: bootstrap, soft, hard`, 400);
745→    }
746→  }
747→
748→  // Validate thresholds if provided
749→  if (thresholds !== undefined) {
750→    if (typeof thresholds !== "object") {
751→      return jsonError("thresholds must be an object", 400);
752→    }
753→    if (thresholds.min_decisions !== undefined) {
754→      if (!Number.isInteger(thresholds.min_decisions) || thresholds.min_decisions < 0) {
755→        return jsonError("thresholds.min_decisions must be a non-negative integer", 400);
756→      }
757→    }
758→    if (thresholds.min_tasks !== undefined) {
759→      if (!Number.isInteger(thresholds.min_tasks) || thresholds.min_tasks < 0) {
760→        return jsonError("thresholds.min_tasks must be a non-negative integer", 400);
761→      }
762→    }
763→  }
764→
765→  try {
766→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
767→
768→    // Read current enforcement mode to detect transitions
769→    const [currentRows] = await deps.surreal.query<[Array<{ evidence_enforcement?: string }>]>(
770→      "SELECT evidence_enforcement FROM $ws;",
771→      { ws: workspaceRecord },
772→    );
773→    const currentMode = currentRows[0]?.evidence_enforcement ?? "bootstrap";
774→
775→    // Build SET clauses for provided fields only
776→    const setClauses: string[] = [];
777→    const bindings: Record<string, unknown> = { ws: workspaceRecord };
778→
779→    if (enforcementMode !== undefined) {
780→      setClauses.push("evidence_enforcement = $mode");
781→      bindings.mode = enforcementMode;
782→
783→      // Append transition entry when mode actually changes
784→      if (enforcementMode !== currentMode) {
785→        const transitionEntry = {
786→          from: currentMode,
787→          to: enforcementMode,
788→          trigger: "manual" as const,
