 20→function useWorkspaceSettings() {
 21→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
 22→  const [settings, setSettings] = useState<WorkspaceSettings | undefined>();
 23→  const [isLoading, setIsLoading] = useState(true);
 24→  const [error, setError] = useState<string | undefined>();
 25→
 26→  const fetchSettings = useCallback(async () => {
 27→    if (!workspaceId) return;
 28→    setIsLoading(true);
 29→    setError(undefined);
 30→    try {
 31→      const response = await fetch(
 32→        `/api/workspaces/${encodeURIComponent(workspaceId)}/settings`,
 33→      );
 34→      if (!response.ok) {
 35→        setError("Failed to load settings");
 36→        return;
 37→      }
 38→      const data = (await response.json()) as WorkspaceSettings;
 39→      setSettings(data);
 40→    } catch {
 41→      setError("Failed to load settings");
 42→    } finally {
 43→      setIsLoading(false);
 44→    }
 45→  }, [workspaceId]);
 46→
 47→  const updateEnforcementMode = useCallback(
 48→    async (mode: string) => {
 49→      if (!workspaceId) return;
 50→      setError(undefined);
 51→      try {
 52→        const response = await fetch(
 53→          `/api/workspaces/${encodeURIComponent(workspaceId)}/settings`,
 54→          {
 55→            method: "PUT",
 56→            headers: { "Content-Type": "application/json" },
 57→            body: JSON.stringify({ enforcementMode: mode }),
 58→          },
 59→        );
 60→        if (!response.ok) {
 61→          setError("Failed to update enforcement mode");
 62→          return;
 63→        }
 64→        await fetchSettings();
 65→      } catch {
 66→        setError("Failed to update enforcement mode");
 67→      }
 68→    },
 69→    [workspaceId, fetchSettings],
 70→  );
 71→
 72→  useEffect(() => {
 73→    void fetchSettings();
 74→  }, [fetchSettings]);
 75→
 76→  const updateThresholds = useCallback(
 77→    async (thresholds: Record<string, number>) => {
 78→      if (!workspaceId) return;
 79→      setError(undefined);
 80→      try {
 81→        const response = await fetch(
 82→          `/api/workspaces/${encodeURIComponent(workspaceId)}/settings`,
 83→          {
 84→            method: "PUT",
 85→            headers: { "Content-Type": "application/json" },
 86→            body: JSON.stringify({ thresholds }),
 87→          },
 88→        );
 89→        if (!response.ok) {
 90→          setError("Failed to update thresholds");
 91→          return;
 92→        }
 93→        await fetchSettings();
 94→      } catch {
 95→        setError("Failed to update thresholds");
 96→      }
 97→    },
 98→    [workspaceId, fetchSettings],
 99→  );
100→
101→  return { settings, isLoading, error, refresh: fetchSettings, updateEnforcementMode, updateThresholds };
102→}
