                    >
                      <span className="text-muted-foreground">{formattedTime}</span>
                      <span className="text-foreground">
                        {transition.from} &rarr; {transition.to}
                      </span>
                      <Badge variant="outline">
                        {transition.trigger}
                      </Badge>
                    </div>
                  );
                })}
              </div>
            </div>
          ) : undefined}
        </div>
      ) : undefined}
    </section>
  );
}

